import{_ as d,c as t,o as i,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.51：Bedrock 跨区域修复、OSC52 剪贴板恢复","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.51.md","filePath":"changelog/v1.1.51.md","lastUpdated":1772014034000}'),h={name:"changelog/v1.1.51.md"};function l(o,e,n,s,c,p){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-51-bedrock-跨区域修复、osc52-剪贴板恢复" tabindex="-1">v1.1.51：Bedrock 跨区域修复、OSC52 剪贴板恢复 <a class="header-anchor" href="#v1-1-51-bedrock-跨区域修复、osc52-剪贴板恢复" aria-label="Permalink to “v1.1.51：Bedrock 跨区域修复、OSC52 剪贴板恢复”">​</a></h1><p><strong>发布日期</strong>：2026年02月04日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次是一个小版本修复，主要解决了 Bedrock 跨区域推理模型的前缀重复问题，恢复了 TUI 的 OSC52 剪贴板支持，并修复了 headers 双重合并的 bug。</p><hr><h2 id="问题修复-bedrock-跨区域推理模型前缀重复" tabindex="-1">问题修复：Bedrock 跨区域推理模型前缀重复 <a class="header-anchor" href="#问题修复-bedrock-跨区域推理模型前缀重复" aria-label="Permalink to “问题修复：Bedrock 跨区域推理模型前缀重复”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>使用 AWS Bedrock 的跨区域推理模型时，模型名称会被错误地添加两次前缀，导致 API 调用失败。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了前缀重复问题，跨区域推理模型现在可以正常使用。</p><hr><h2 id="问题修复-provider-headers-双重合并" tabindex="-1">问题修复：Provider Headers 双重合并 <a class="header-anchor" href="#问题修复-provider-headers-双重合并" aria-label="Permalink to “问题修复：Provider Headers 双重合并”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>如果一个 provider 在多个地方配置了认证信息，headers 会被重复合并，可能导致请求异常。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>回退了导致 headers 双重合并的变更，认证信息现在正确处理。</p><hr><h2 id="改进-tui-恢复-osc52-剪贴板" tabindex="-1">改进：TUI 恢复 OSC52 剪贴板 <a class="header-anchor" href="#改进-tui-恢复-osc52-剪贴板" aria-label="Permalink to “改进：TUI 恢复 OSC52 剪贴板”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>恢复了 TUI 对 OSC52 剪贴板协议的直接支持。</p><h3 id="有什么用" tabindex="-1">有什么用？ <a class="header-anchor" href="#有什么用" aria-label="Permalink to “有什么用？”">​</a></h3><p>OSC52 是一种终端剪贴板协议，允许在远程 SSH 会话中也能正常复制内容到本地剪贴板。如果你经常通过 SSH 使用 OpenCode，这个功能非常实用。</p><hr><h2 id="改进-agents-md-配置目录优先级" tabindex="-1">改进：AGENTS.md 配置目录优先级 <a class="header-anchor" href="#改进-agents-md-配置目录优先级" aria-label="Permalink to “改进：AGENTS.md 配置目录优先级”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在 <code>OPENCODE_CONFIG_DIR</code> 环境变量指定的目录会被优先用于查找 AGENTS.md 文件。</p><h3 id="有什么用-1" tabindex="-1">有什么用？ <a class="header-anchor" href="#有什么用-1" aria-label="Permalink to “有什么用？”">​</a></h3><p>如果你通过环境变量自定义了配置目录，AGENTS.md 会优先从该目录读取，而不是默认位置。</p><hr><h2 id="改进-内置-agent-文档" tabindex="-1">改进：内置 Agent 文档 <a class="header-anchor" href="#改进-内置-agent-文档" aria-label="Permalink to “改进：内置 Agent 文档”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>新增了内置 Agent 的官方文档，帮助用户了解 OpenCode 自带的 Agent 功能。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 AWS Bedrock 跨区域推理</td><td>✅ 强烈推荐</td></tr><tr><td>通过 SSH 使用 OpenCode</td><td>✅ 推荐升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',37),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Revert change that caused headers to be double merged if provider was authenticated in multiple places</li><li>Document the built-in agents</li><li>Prevent double-prefixing of Bedrock cross-region inference models (@sergical)</li><li>Prioritize OPENCODE_CONFIG_DIR for AGENTS.md (@lgladysz)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Restore direct OSC52 support</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Tighten up session padding-top for mobile (@DNGriffin)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const k=d(h,[["render",l]]);export{m as __pageData,k as default};
